import { Component, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { catchError, of } from 'rxjs';

import { AppStoreService } from '../../services/app-store.service';
import { AppDefinition } from '../../models/app-store.models';
import { AuthDataService } from '../../../../core/services/auth-data.service';
import {
  getStatusSeverity,
  getStatusLabel,
} from '../../utils/status.utils';

import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';
import { TagModule } from 'primeng/tag';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { TableModule } from 'primeng/table';

@Component({
  selector: 'app-app-creator-dashboard',
  imports: [
    CommonModule,
    RouterModule,
    ButtonModule,
    CardModule,
    TagModule,
    ProgressSpinnerModule,
    TableModule,
  ],
  templateUrl: './app-creator-dashboard.component.html',
  styleUrls: ['./app-creator-dashboard.component.scss'],
})
export class AppCreatorDashboardComponent {
  private readonly appStoreService = inject(AppStoreService);
  private readonly authDataService = inject(AuthDataService);

  // State Signals
  readonly isLoading = signal(true);
  readonly error = signal<string | null>(null);
  readonly apps = signal<AppDefinition[]>([]);

  constructor() {
    this.loadApps();
  }

  private loadApps(): void {
    this.isLoading.set(true);
    this.error.set(null);

    this.appStoreService
      .getApps()
      .pipe(
        catchError(() => {
          this.error.set('Unable to load your apps. Please try again.');
          return of([] as AppDefinition[]);
        }),
      )
      .subscribe((apps) => {
        this.apps.set(apps);
        this.isLoading.set(false);
      });
  }

  // Delegate to shared utility functions
  readonly statusSeverity = getStatusSeverity;
  readonly statusLabel = getStatusLabel;

  reload(): void {
    this.loadApps();
  }
}
